[PostHandlerFor(classStr(PurchFormLetter_PurchOrder), methodStr(PurchFormLetter_PurchOrder, validate))]
public static void PurchFormLetter_PurchOrder_Post_validate(XppPrePostArgs args)
{
    boolean ret = args.getReturnValue();
    PurchFormLetter_PurchOrder formLetter = args.getThis() as PurchFormLetter_PurchOrder;


    if(ETG_Parameters::find().UnitPriceValidation == NoYes::Yes)
    {
        if (ret)
        {
            PurchTable purchTable = formLetter.purchTable();
            PurchLine purchLine;

            while select LineNumber, PurchPrice from purchLine
            where purchLine.PurchId == purchTable.PurchId
               && purchLine.IsDeleted == NoYes::No
            {
                if (!purchLine.PurchPrice)
                {
                    ret = checkFailed(strFmt("Unit price must be filled for line %1.", purchLine.LineNumber));
                    break;
                }
            }
            args.setReturnValue(ret);
        }
    }
}
